import{_ as e,o as n,c as a,a2 as l}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"F02: 營業現金流與獲利品質 - finance-financial-analyst 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3135_凌航/20260430/F02_營業現金流與獲利品質_財務分析專家.md","filePath":"審計報告庫/財務審計/3135_凌航/20260430/F02_營業現金流與獲利品質_財務分析專家.md"}'),s={name:"審計報告庫/財務審計/3135_凌航/20260430/F02_營業現金流與獲利品質_財務分析專家.md"};function r(i,t,d,c,o,g){return n(),a("div",null,[...t[0]||(t[0]=[l(`<h1 id="f02-營業現金流與獲利品質-finance-financial-analyst-審計報告" tabindex="-1">F02: 營業現金流與獲利品質 - finance-financial-analyst 審計報告 <a class="header-anchor" href="#f02-營業現金流與獲利品質-finance-financial-analyst-審計報告" aria-label="Permalink to &quot;F02: 營業現金流與獲利品質 - finance-financial-analyst 審計報告&quot;">​</a></h1><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>營業活動現金流量 (CFO) 與稅後淨利之關係為何？獲利是否具備實質現金支撐？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：CFO/NI 從 FY2024 +402% 暴跌至 FY2025 -286%，獲利 445.9M 全數為「紙上富貴」——全年 CFO 負 1,275.5M，存貨膨脹 1,879M 與應收帳款增加 600M 吞噬全部利潤。</li><li><strong>風險評級</strong>：高</li><li><strong>數據時效</strong>：根據截至 2025 年最新公開數據</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><h3 id="重點數據-單位-新台幣千元" tabindex="-1">重點數據 (單位：新台幣千元) <a class="header-anchor" href="#重點數據-單位-新台幣千元" aria-label="Permalink to &quot;重點數據 (單位：新台幣千元)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">指標</th><th style="text-align:center;">FY2022</th><th style="text-align:center;">FY2023</th><th style="text-align:center;">FY2024</th><th style="text-align:center;">FY2025</th></tr></thead><tbody><tr><td style="text-align:left;">營業收入</td><td style="text-align:center;">3,582,728</td><td style="text-align:center;">4,221,573</td><td style="text-align:center;">5,507,775</td><td style="text-align:center;">5,144,362</td></tr><tr><td style="text-align:left;">營收 YoY</td><td style="text-align:center;">—</td><td style="text-align:center;">+17.8%</td><td style="text-align:center;">+30.5%</td><td style="text-align:center;">-6.6%</td></tr><tr><td style="text-align:left;">稅後淨利 (NI)</td><td style="text-align:center;">18,344</td><td style="text-align:center;">78,087</td><td style="text-align:center;">142,410</td><td style="text-align:center;">445,911</td></tr><tr><td style="text-align:left;">營業活動現金流 (CFO)</td><td style="text-align:center;">635,765</td><td style="text-align:center;">-909,486</td><td style="text-align:center;">572,049</td><td style="text-align:center;">-1,275,502</td></tr><tr><td style="text-align:left;"><strong>CFO/淨利比</strong></td><td style="text-align:center;"><strong>3,474%</strong></td><td style="text-align:center;"><strong>-1,164%</strong></td><td style="text-align:center;"><strong>402%</strong></td><td style="text-align:center;"><strong>-286%</strong></td></tr><tr><td style="text-align:left;">折舊攤銷 (D&amp;A)</td><td style="text-align:center;">9,352</td><td style="text-align:center;">9,299</td><td style="text-align:center;">10,183</td><td style="text-align:center;">9,881</td></tr><tr><td style="text-align:left;">資本支出 (CapEx)</td><td style="text-align:center;">2,923</td><td style="text-align:center;">3,613</td><td style="text-align:center;">620,665</td><td style="text-align:center;">51,789</td></tr><tr><td style="text-align:left;">自由現金流 (FCF)</td><td style="text-align:center;">632,842</td><td style="text-align:center;">-913,099</td><td style="text-align:center;">-48,616</td><td style="text-align:center;">-1,327,291</td></tr><tr><td style="text-align:left;">應收帳款變動影響</td><td style="text-align:center;">+193,525</td><td style="text-align:center;">-624,439</td><td style="text-align:center;">+11,723</td><td style="text-align:center;">-600,120</td></tr><tr><td style="text-align:left;">存貨變動影響</td><td style="text-align:center;">+241,972</td><td style="text-align:center;">-308,343</td><td style="text-align:center;">-75,317</td><td style="text-align:center;">-1,879,125</td></tr><tr><td style="text-align:left;">短期借款</td><td style="text-align:center;">195,900</td><td style="text-align:center;">720,476</td><td style="text-align:center;">698,641</td><td style="text-align:center;">1,221,007</td></tr><tr><td style="text-align:left;">長期借款</td><td style="text-align:center;">0</td><td style="text-align:center;">26,250</td><td style="text-align:center;">421,775</td><td style="text-align:center;">402,400</td></tr><tr><td style="text-align:left;">應付公司債</td><td style="text-align:center;">0</td><td style="text-align:center;">0</td><td style="text-align:center;">0</td><td style="text-align:center;">937,507</td></tr><tr><td style="text-align:left;">資產總額</td><td style="text-align:center;">1,351,487</td><td style="text-align:center;">2,090,020</td><td style="text-align:center;">2,545,672</td><td style="text-align:center;">5,178,900</td></tr><tr><td style="text-align:left;">負債比率</td><td style="text-align:center;">20.2%</td><td style="text-align:center;">46.7%</td><td style="text-align:center;">53.0%</td><td style="text-align:center;">59.0%</td></tr></tbody></table><h3 id="診斷見解" tabindex="-1">診斷見解 <a class="header-anchor" href="#診斷見解" aria-label="Permalink to &quot;診斷見解&quot;">​</a></h3><p><strong>核心矛盾：營收微降 6.6%，NI 暴增 213% 至 445.9M，CFO 卻反向崩至 -1,275.5M。</strong> 存貨從 714M 暴增至 2,619M（+1,879M），應收帳款從 882M 增至 1,499M（+600M），兩項合計吞噬 2,479M 現金，NI 全數為紙上富貴。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="子議題一-cfo-ni-比值四年軌跡——從「超額造血」到「失血求生」" tabindex="-1">子議題一：CFO/NI 比值四年軌跡——從「超額造血」到「失血求生」 <a class="header-anchor" href="#子議題一-cfo-ni-比值四年軌跡——從「超額造血」到「失血求生」" aria-label="Permalink to &quot;子議題一：CFO/NI 比值四年軌跡——從「超額造血」到「失血求生」&quot;">​</a></h3><ul><li><strong>核心重點</strong>：四年比值 +3,474% → -1,164% → +402% → -286%，呈現記憶體模組廠「景氣循環」特徵——獲利高峰年反而是現金流低谷年（FY2025），因價格上漲前必須大量備貨。</li><li><strong>深度見解</strong>：FY2025 存貨膨脹（+1,879M）是 FY2023（+308M）的 6 倍，但營收僅增 21%，顯示「每元營收占用的營運資金」急劇惡化，獲利含金量持續惡化。</li></ul><h3 id="子議題二-非現金項目核實——折舊僅-9-9m-無法「遮掩」任何東西" tabindex="-1">子議題二：非現金項目核實——折舊僅 9.9M，無法「遮掩」任何東西 <a class="header-anchor" href="#子議題二-非現金項目核實——折舊僅-9-9m-無法「遮掩」任何東西" aria-label="Permalink to &quot;子議題二：非現金項目核實——折舊僅 9.9M，無法「遮掩」任何東西&quot;">​</a></h3><ul><li><strong>核心重點</strong>：D&amp;A 四年維持 9-10M（佔 NI 從 51% 降至 2.2%），CapEx FY2024 因新廠設備暴增至 620.7M，FY2025 驟降至 51.8M。</li><li><strong>深度見解</strong>：凌航為輕資產組裝型企業，D&amp;A 對 CFO 支撐極有限（僅佔營運現金流 0.78%），FY2025 的 CFO -1,275.5M 幾乎 100% 來自營運資金變動，獲利含金量完全取決於存貨與應收管控。</li></ul><h3 id="子議題三-營運資金結構——存貨暴增-188-應收增-70-現金幾乎歸零" tabindex="-1">子議題三：營運資金結構——存貨暴增 188%，應收增 70%，現金幾乎歸零 <a class="header-anchor" href="#子議題三-營運資金結構——存貨暴增-188-應收增-70-現金幾乎歸零" aria-label="Permalink to &quot;子議題三：營運資金結構——存貨暴增 188%，應收增 70%，現金幾乎歸零&quot;">​</a></h3><ul><li><strong>核心重點</strong>：FY2025 存貨從 714M 暴增至 2,619M（+191%），應收帳款從 882M 增至 1,499M（+70%），期末現金僅剩 60.8M；存貨+應收合計佔總資產 79.5%。</li><li><strong>深度見解</strong>：公司以 2,561M 借款組合支撐存貨擴張，負債比率升至 59%；若 DRAM/NAND 價格回落，2,619M 存貨面臨跌價壓力，現金僅 60.8M，流動性緩衝極度薄弱。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一：存貨跌價地雷。</strong> FY2025 存貨 2,619M 佔營收的 50.9%（遠高於 FY2024 的 13%），若記憶體價格在 FY2026 下跌 10%，將產生約 262M 的潛在跌價損失，相當於 FY2025 NI 的 58.7%。更嚴峻的是，公司已發行 937.5M 應付公司債，若存貨價值縮水導致融資機構要求提前償還或收緊授信，可能觸發流動性危機。壓力測試：假設存貨跌價 15% + 應收帳款壞帳 5%，合計損失約 470M，將直接侵蝕 105% 的 FY2025 淨利。</li><li><strong>空頭風險二：營運資金黑洞惡性循環。</strong> FY2025 現金僅 60.8M，而單季營收約 12.9 億，意味著公司幾乎完全依賴銀行融資維持日常周轉。若記憶體市場需求放缓（如 AI 伺服器建置高峰過後），營收下滑將導致存貨周轉天數拉長，進而需要更多融資填補缺口。從月營收觀察，2026 年 1-3 月營收分別為 15.5 億、9.8 億、14.3 億，波動劇烈，若 Q2 進入淡季，存貨壓力將進一步加劇。</li><li><strong>空頭風險三：應付公司債的償還壓力。</strong> 937.5M 應付公司債為 FY2025 新增，佔總負債 30.7%。若公司未能在債券到期前將存貨有效轉化為現金（即存貨周轉效率未改善），將面臨「借新債還舊債」的滾雪球風險。對比 FY2024 無公司債的資本結構，FY2025 的財務槓桿已顯著提升。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind (cash_flow)</strong>：OK。完整提取 FY2022-FY2025 四年度現金流量表原始數據。</li><li><strong>FinMind (finance)</strong>：OK。完整提取 FY2022-FY2025 四年度損益表原始數據。</li><li><strong>FinMind (balance_sheet)</strong>：OK。完整提取資產負債表，用於交叉驗證存貨、應收、負債餘額。</li><li><strong>Web Search (cmoney/StatementDog)</strong>：OK。交叉比對確認 2025 全年營收 77.04 億、NI 4.46 億、CFO/NI 比值 -374.59% 等核心數據。</li><li><strong>關鍵核對碼</strong>：<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>FY2025: CFO -1,275,502 千元 | NI 445,911 千元 | 比值 -286%</span></span>
<span class="line"><span>FY2024: CFO 572,049 千元 | NI 142,410 千元 | 比值 402%</span></span>
<span class="line"><span>FY2023: CFO -909,486 千元 | NI 78,087 千元 | 比值 -1,164%</span></span>
<span class="line"><span>FY2022: CFO 635,765 千元 | NI 18,344 千元 | 比值 3,474%</span></span>
<span class="line"><span>FY2025 存貨: 2,618,809 千元 (YoY +191%) | 應收: 1,499,132 千元 (YoY +70%)</span></span>
<span class="line"><span>FY2025 期末現金: 60,849 千元 | 負債比: 59.0%</span></span></code></pre></div></li></ul><hr><p><strong>報告落地路徑</strong>：<code>/Users/kaipro/.openclaw/skills/NEW_Deep32Q/審計報告庫/3135_凌航/20260430/財務組/F02_營業現金流與獲利品質_財務分析專家.md</code></p>`,24)])])}const h=e(s,[["render",r]]);export{y as __pageData,h as default};
